import React, { useEffect, useState } from "react";
import { Trash2, Pencil, Plus, Search, X } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { linkHomeDesign as design } from "../../design/linkHomeDesign";

const API = "http://localhost:5000/api/links";

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [filteredLinks, setFilteredLinks] = useState([]);
  const [name, setName] = useState("");
  const [order, setOrder] = useState(0);
  const [isActive, setIsActive] = useState(true);
  const [editingId, setEditingId] = useState(null);
  const [showForm, setShowForm] = useState(false);
  const [search, setSearch] = useState("");

  /* ================= FETCH ================= */
  const fetchLinks = async () => {
    try {
      const res = await fetch(API);
      const data = await res.json();

      const parentLinks = data
        .filter((link) => !link.parent)
        .sort((a, b) => a.order - b.order);

      setLinks(parentLinks);
      setFilteredLinks(parentLinks);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchLinks();
  }, []);

  /* ================= SEARCH ================= */
  useEffect(() => {
    const result = links.filter((link) =>
      link.name.toLowerCase().includes(search.toLowerCase())
    );
    setFilteredLinks(result);
  }, [search, links]);

  /* ================= SUBMIT ================= */
  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!name.trim()) return;

    const payload = { name, order, isActive, parent: null };

    try {
      if (editingId) {
        await fetch(`${API}/${editingId}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        });
      } else {
        await fetch(API, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        });
      }

      resetForm();
      fetchLinks();
    } catch (err) {
      console.error(err);
    }
  };

  const handleEdit = (link) => {
    setName(link.name);
    setOrder(link.order);
    setIsActive(link.isActive);
    setEditingId(link._id);
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    await fetch(`${API}/${id}`, { method: "DELETE" });
    fetchLinks();
  };

  const resetForm = () => {
    setName("");
    setOrder(0);
    setIsActive(true);
    setEditingId(null);
    setShowForm(false);
  };

  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>
        
        {/* HEADER */}
        <div className={design.header}>
          <div>
            <h1 className={design.title}>Parent Navigation Links</h1>
            <p className={design.subtitle}>
              Manage main menu items only.
            </p>
            <p className={design.path}>linkhome/</p>
          </div>
        </div>

        {/* NAVBAR */}
        <div className={design.navbar}>
          <div className={design.searchWrapper}>
            <Search size={16} />
            <input
              type="text"
              placeholder="Search link..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className={design.searchInput}
            />
          </div>

          <button
            onClick={() => setShowForm(!showForm)}
            className={design.addButton}
          >
            <Plus size={16} />
            Add Link
          </button>
        </div>

        {/* FORM */}
        <AnimatePresence>
          {showForm && (
            <motion.form
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              onSubmit={handleSubmit}
              className={design.form}
            >
              <input
                type="text"
                placeholder="Link Name"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className={design.input}
              />

              <input
                type="number"
                placeholder="Order"
                value={order}
                onChange={(e) => setOrder(Number(e.target.value))}
                className={design.input}
              />

              <select
                value={isActive}
                onChange={(e) => setIsActive(e.target.value === "true")}
                className={design.input}
              >
                <option value="true">Active</option>
                <option value="false">Inactive</option>
              </select>

              <button type="submit" className={design.submitButton}>
                {editingId ? "Update" : "Create"}
              </button>

              <button
                type="button"
                onClick={resetForm}
                className={design.cancelButton}
              >
                <X size={16} />
              </button>
            </motion.form>
          )}
        </AnimatePresence>

        {/* TABLE */}
        <div className={design.table}>
          {filteredLinks.map((link) => (
            <div key={link._id} className={design.row}>
              <div>{link.name}</div>
              <div>{link.order}</div>
              <div>{link.isActive ? "Active" : "Inactive"}</div>
              <div className="flex gap-4 justify-end">
                <Pencil size={16} onClick={() => handleEdit(link)} className="cursor-pointer" />
                <Trash2 size={16} onClick={() => handleDelete(link._id)} className="cursor-pointer text-red-500" />
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default LinkHome;
